UPDATE public.questions SET
  stimulus_text = 'The early 1900s were a time of great change in the United States, as the country dealt with the effects of industrialization, urbanization, and immigration. Many people were drawn to cities for jobs and opportunities, but others were wary of the social and economic upheaval brought by the industrial revolution. Some people embraced progress and new ideas, while others clung to traditional values. This period saw a surge in social movements that challenged the status quo and demanded change.  The Industrial Revolution ushered in a new era of technological advancement, and factories began to dominate the landscape. This led to a rise in the number of people who worked in factories, and the cities swelled with new arrivals from rural areas and other countries. The economic changes brought by the Industrial Revolution created both opportunities and challenges.  While some people welcomed the new technologies and the economic prosperity that they brought, others were concerned about the negative social and environmental consequences of industrialization.  The growth of factories and cities created new problems, such as pollution, overcrowding, and crime.',
  question_text = 'Which sentence best summarizes the author''s perspective on the Industrial Revolution in the United States?',
  stimulus_type = NULL,
